// =============================================================================
// Error Utilities
// =============================================================================

/**
 * Type guard to check if an error is an MmsError
 */
export function isMmsError(error: unknown): error is MmsError {
  return error instanceof MmsError;
}

/**
 * Convert unknown error to MmsError
 */
export function toMmsError(error: unknown): MmsError {
  if (isMmsError(error)) {
    return error;
  }

  if (error instanceof Error) {
    return new SystemError(error.message, {
      originalError: error.name,
      stack: error.stack,
    });
  }

  return new SystemError(String(error));
}

