   584→export function parseMileageCsvRow(
   585→  row: unknown
   586→): { success: true; data: ParsedMileageCsvRow } | { success: false; errors: ValidationError[] } {
   587→  const errors: ValidationError[] = [];
   588→
   589→  if (!row || typeof row !== 'object') {
   590→    return { success: false, errors: [{ field: 'row', message: 'Invalid row data' }] };
   591→  }
   592→
   593→  const r = row as Record<string, unknown>;
   594→  const trainNumber = String(r['train_number'] || '');
   595→  const readingDate = String(r['reading_date'] || '');
   596→  const odometerKmStr = String(r['odometer_km'] || '');
   597→
   598→  if (!trainNumber) {
   599→    errors.push({ field: 'train_number', message: 'Train number required' });
   600→  }
   601→  if (!isValidDateString(readingDate)) {
   602→    errors.push({ field: 'reading_date', message: 'Date must be in YYYY-MM-DD format' });
   603→  }
   604→
   605→  const odometerKm = parseInt(odometerKmStr, 10);
   606→  if (isNaN(odometerKm) || !isValidMileage(odometerKm)) {
   607→    errors.push({ field: 'odometer_km', message: 'Mileage must be 0-10,000,000 km' });
   608→  }
   609→
   610→  if (errors.length > 0) {
   611→    return { success: false, errors };
   612→  }
   613→
   614→  return {
   615→    success: true,
   616→    data: {
   617→      trainNumber,
   618→      readingDate,
   619→      odometerKm,
   620→    },
   621→  };
   622→}
