});

const OPTIMIZER_OUTPUT_TYPES = ['PROGRESS', 'HEARTBEAT', 'ERROR', 'RESULT'] as const;

/**
 * Parse optimizer output message
 */
export function parseOptimizerOutput(
  data: unknown
): { success: true; data: OptimizerOutput } | { success: false; errors: ValidationError[] } {
  if (!data || typeof data !== 'object') {
    return { success: false, errors: [{ field: 'data', message: 'Invalid optimizer output' }] };
  }

  const d = data as Record<string, unknown>;
  const type = d['type'];

  if (!OPTIMIZER_OUTPUT_TYPES.includes(type as (typeof OPTIMIZER_OUTPUT_TYPES)[number])) {
    return { success: false, errors: [{ field: 'type', message: 'Invalid optimizer output type' }] };
  }

  switch (type) {
    case 'PROGRESS':
      return { success: true, data: optimizerProgressSchema.parse(data) as OptimizerProgress };
    case 'HEARTBEAT':
      return { success: true, data: optimizerHeartbeatSchema.parse(data) as OptimizerHeartbeat };
    case 'ERROR':
      return { success: true, data: optimizerErrorSchema.parse(data) as OptimizerError };
    case 'RESULT':
      return { success: true, data: optimizerResultSchema.parse(data) as OptimizerResult };
    default:
      return { success: false, errors: [{ field: 'type', message: 'Unknown output type' }] };
  }
}

/**
 * Validate optimizer input
 */
export function validateOptimizerInput(
  data: OptimizerInput
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidDateString(data.date)) {
    errors.push({ field: 'date', message: 'Date must be in YYYY-MM-DD format' });
  }
  if (!isValidUuid(data.fleetId)) {
    errors.push({ field: 'fleetId', message: 'Invalid UUID format' });
  }
  if (!Array.isArray(data.trains) || data.trains.length === 0) {
    errors.push({ field: 'trains', message: 'At least one train required' });
  }
  if (!Array.isArray(data.routes) || data.routes.length === 0) {
    errors.push({ field: 'routes', message: 'At least one route required' });
  }

  return { valid: errors.length === 0, errors };
}

