/**
 * MMS Redis Connection
 *
 * Provides Redis connection utilities for:
 * - BullMQ job queues
 * - Session storage
 * - Caching layer
 *
 * @see specs/003-database-schema.md Section 3.2
 */

import Redis, { type RedisOptions } from 'ioredis';

export interface RedisConfig {
  host: string;
  port: number;
  password?: string;
  db?: number;
  maxRetriesPerRequest: number | null;
  enableReadyCheck: boolean;
  lazyConnect?: boolean;
  keyPrefix?: string;
}

const defaultConfig: RedisConfig = {
  host: process.env['REDIS_HOST'] ?? 'localhost',
  port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
  password: process.env['REDIS_PASSWORD'],
  db: parseInt(process.env['REDIS_DB'] ?? '0', 10),
  maxRetriesPerRequest: null, // Required for BullMQ
  enableReadyCheck: true,
  lazyConnect: false,
};

let redisClient: Redis | null = null;
let bullmqConnection: Redis | null = null;

/**
 * Get or create the main Redis client
 * Used for caching and general operations
 */
export function getRedisClient(config: Partial<RedisConfig> = {}): Redis {
  if (!redisClient) {
    const mergedConfig: RedisOptions = {
      ...defaultConfig,
      ...config,
      keyPrefix: config.keyPrefix ?? 'mms:',
    };
    redisClient = new Redis(mergedConfig);

    redisClient.on('error', (err) => {
      console.error('[Redis] Connection error:', err.message);
    });

    redisClient.on('connect', () => {
      console.info('[Redis] Connected successfully');
    });

    redisClient.on('ready', () => {
      console.info('[Redis] Ready to accept commands');
    });
  }

  return redisClient;
}

/**
 * Get or create a Redis connection for BullMQ
 * Separate instance to avoid blocking queue operations
 */
export function getBullMQConnection(config: Partial<RedisConfig> = {}): Redis {
  if (!bullmqConnection) {
    const mergedConfig: RedisOptions = {
      ...defaultConfig,
      ...config,
      maxRetriesPerRequest: null, // Critical for BullMQ
      enableReadyCheck: false, // Faster startup for workers
    };
    bullmqConnection = new Redis(mergedConfig);

    bullmqConnection.on('error', (err) => {
      console.error('[BullMQ Redis] Connection error:', err.message);
    });
  }

  return bullmqConnection;
}

/**
 * Check Redis health
 */
export async function checkRedisHealth(): Promise<boolean> {
  try {
    const client = getRedisClient();
    const result = await client.ping();
    return result === 'PONG';
  } catch {
    return false;
  }
}

/**
 * Close all Redis connections
 * Call during graceful shutdown
 */
export async function closeRedisConnections(): Promise<void> {
  const closePromises: Promise<void>[] = [];

  if (redisClient) {
    closePromises.push(
      redisClient.quit().then(() => {
        redisClient = null;
      })
    );
  }

  if (bullmqConnection) {
    closePromises.push(
      bullmqConnection.quit().then(() => {
        bullmqConnection = null;
      })
    );
  }

  await Promise.all(closePromises);
  console.info('[Redis] All connections closed');
}

/**
 * Cache utilities
 */
export const cache = {
  /**
   * Get cached value
   */
  async get<T>(key: string): Promise<T | null> {
    const client = getRedisClient();
    const value = await client.get(key);
    if (!value) return null;
    try {
      return JSON.parse(value) as T;
    } catch {
      return value as unknown as T;
    }
  },

  /**
   * Set cached value with optional TTL
   */
  async set<T>(key: string, value: T, ttlSeconds?: number): Promise<void> {
    const client = getRedisClient();
    const serialized = typeof value === 'string' ? value : JSON.stringify(value);
    if (ttlSeconds) {
      await client.setex(key, ttlSeconds, serialized);
    } else {
      await client.set(key, serialized);
    }
  },

  /**
   * Delete cached value
   */
  async del(key: string): Promise<void> {
    const client = getRedisClient();
    await client.del(key);
  },

  /**
   * Delete multiple keys by pattern
   */
  async delByPattern(pattern: string): Promise<number> {
    const client = getRedisClient();
    const keys = await client.keys(pattern);
    if (keys.length === 0) return 0;
    return client.del(...keys);
  },
};

/**
 * MMS Database Connection
 *
 * PostgreSQL connection pool using postgres.js driver with Drizzle ORM.
 * Configured for production use with health checks and connection limits.
 *
 * Environment Variables:
 * - DATABASE_URL: PostgreSQL connection string (required)
 * - DATABASE_MAX_CONNECTIONS: Max pool size (default: 20)
 * - DATABASE_SSL: Enable SSL (default: true in production)
 *
 * @see specs/008-operations-deployment.md for production configuration
 */

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import * as schema from './schema';

/**
 * Database configuration from environment
 */
const config = {
  url: process.env['DATABASE_URL'] ?? 'postgresql://mms:mms@localhost:5432/mms_dev',
  maxConnections: parseInt(process.env['DATABASE_MAX_CONNECTIONS'] ?? '20', 10),
  ssl: process.env['DATABASE_SSL'] === 'true' || process.env['NODE_ENV'] === 'production',
  idleTimeout: 20, // seconds
  connectTimeout: 10, // seconds
};

/**
 * PostgreSQL connection pool
 *
 * Using postgres.js for:
 * - Native ESM support
 * - Excellent TypeScript support
 * - Prepared statements
 * - Connection pooling
 */
export const sql = postgres(config.url, {
  max: config.maxConnections,
  idle_timeout: config.idleTimeout,
  connect_timeout: config.connectTimeout,
  ssl: config.ssl ? { rejectUnauthorized: false } : false,
  // Prepare statements for better performance
  prepare: true,
  // Transform column names from snake_case to camelCase
  // Note: Drizzle handles this, so we keep original names
  transform: {
    undefined: null,
  },
  // Connection event handlers for logging/monitoring
  onnotice: () => {
    // Suppress notices in production
  },
});

/**
 * Drizzle ORM instance
 *
 * Provides type-safe query builder with full schema awareness.
 * All queries automatically use the connection pool.
 */
export const db = drizzle(sql, {
  schema,
  logger: process.env['NODE_ENV'] === 'development',
});

/**
 * Database health check
 *
 * Use this for liveness/readiness probes in Kubernetes.
 * Returns true if the database is reachable and responsive.
 */
export async function checkDatabaseHealth(): Promise<boolean> {
  try {
    const result = await sql`SELECT 1 as health`;
    return result.length === 1 && result[0]?.health === 1;
  } catch {
    return false;
  }
}

/**
 * Graceful shutdown
 *
 * Close all database connections gracefully.
 * Call this during application shutdown.
 */
export async function closeDatabaseConnection(): Promise<void> {
  await sql.end();
}

/**
 * Database transaction helper
 *
 * Executes a function within a database transaction.
 * Automatically commits on success or rolls back on error.
 *
 * @example
 * const result = await withTransaction(async (tx) => {
 *   await tx.insert(trains).values({ ... });
 *   await tx.insert(pmSchedule).values({ ... });
 *   return { success: true };
 * });
 */
export type Transaction = Parameters<Parameters<typeof db.transaction>[0]>[0];

export async function withTransaction<T>(
  fn: (tx: Transaction) => Promise<T>
): Promise<T> {
  return db.transaction(async (tx) => fn(tx));
}

// Export types for use in services
export type Database = typeof db;

